; [AI] 16-bit compare-by-subtraction of two memory-resident pointers: loads the word at (BC),
;       subtracts it from the word at (DE), returning carry to signal which pointer is larger (loop-
;       termination test).
SUB_079D:
        LD L,C                           ; $079D  69
        LD H,B                           ; $079E  60
        LD C,(HL)                        ; $079F  4E
        INC HL                           ; $07A0  23
        LD B,(HL)                        ; $07A1  46
        LD A,(DE)                        ; $07A2  1A
        SUB C                            ; $07A3  91
        LD L,A                           ; $07A4  6F
        INC DE                           ; $07A5  13
        LD A,(DE)                        ; $07A6  1A
        SBC A,B                          ; $07A7  98
        LD H,A                           ; $07A8  67
        RET                              ; $07A9  C9
; [AI] Computes HL = word at (DE) minus the byte in A, a mixed 8/16-bit subtraction used when
;       checking the high-load-address bound.
SUB_07AA:
        LD L,A                           ; $07AA  6F
        LD H,$00                         ; $07AB  26 00
        LD A,(DE)                        ; $07AD  1A
        SUB L                            ; $07AE  95
        LD L,A                           ; $07AF  6F
        INC DE                           ; $07B0  13
        LD A,(DE)                        ; $07B1  1A
        SBC A,H                          ; $07B2  9C
        LD H,A                           ; $07B3  67
        RET                              ; $07B4  C9
        DEFB    $5F,$16,$00                                      ; $07B5
; [AI] 16-bit subtraction of the word at (HL) from DE, returning the result in HL with carry set,
;       used to test whether the current address has crossed a record/page boundary.
SUB_07B8:
        LD A,E                           ; $07B8  7B
SUB_07B8_1:
        SUB (HL)                         ; $07B9  96
SUB_07B8_2:
        LD E,A                           ; $07BA  5F
SUB_07B8_3:
        LD A,D                           ; $07BB  7A
SUB_07B8_4:
        INC HL                           ; $07BC  23
SUB_07B8_5:
        SBC A,(HL)                       ; $07BD  9E
SUB_07B8_6:
        LD D,A                           ; $07BE  57
SUB_07B8_7:
        EX DE,HL                         ; $07BF  EB
SUB_07B8_8:
        RET                              ; $07C0  C9
        DEFS    38, $1A    ; $07C1  fill
SUB_07B8_9:
        DEFB    $1A,$1A                                          ; $07E7
SUB_07B8_10:
        DEFS    9, $1A    ; $07E9  fill
SUB_07B8_11:
        DEFS    14, $1A    ; $07F2  fill

    SAVEBIN "LOAD.bin", $0100, $0700
